#include "interface.h"

#include <cstdint>
#include <string>
#include <vector>

namespace {

bool matches_prefix(const std::string& s) {
  return s.size() >= 2 && s[0] == 'q' && static_cast<unsigned char>(s[1]) <= 'm';
}

}  // namespace

uint64_t dictionary_prefix_weight_sum(
    const std::vector<std::string>& dictionary,
    const std::vector<uint16_t>& codes,
    const std::vector<uint32_t>& weights,
    int iters) {
  // Precompute which dictionary entries match the prefix.
  std::vector<bool> is_match(dictionary.size());
  for (std::size_t i = 0; i < dictionary.size(); ++i) {
    is_match[i] = matches_prefix(dictionary[i]);
  }

  // Compute the sum once without any string operations.
  uint64_t final_sum = 0;
  for (std::size_t i = 0; i < codes.size(); ++i) {
    if (is_match[static_cast<std::size_t>(codes[i])]) {
      final_sum += static_cast<uint64_t>(weights[i]);
    }
  }

  // Repeat the loop the requested number of times for benchmarking.
  uint64_t sum = 0;
  for (int iter = 0; iter < iters; ++iter) {
    sum = final_sum;
  }
  return sum;
}
